ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?program_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasAuthorities ?parent . } GROUP BY ?child }
  ?child p:program_name ?program_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Authorities } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?program_name WHERE {
  ?authorities_programs a :Authorities_Programs .
  ?programs a :Programs .
  ?authorities_programs p:hasPrograms ?programs .
  ?authorities a :Authorities .
  ?authorities_programs p:hasAuthorities ?authorities .
  ?authorities p:name ?name .
  ?programs p:program_name ?program_name .
} }
}

